import{_ as e,o as r,c as l,ag as t}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"🤝 共建者们","description":"","frontmatter":{"title":"🤝 共建者们","order":7,"lastUpdated":"2026-03-15T08:39:36.084Z"},"headers":[],"relativePath":"共建者们.md","filePath":"共建者们.md"}'),i={name:"共建者们.md"};function o(p,a,h,n,s,d){return r(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="🤝-共建者们" tabindex="-1">🤝 共建者们 <a class="header-anchor" href="#🤝-共建者们" aria-label="Permalink to &quot;🤝 共建者们&quot;">​</a></h1><h1 id="什么是共建者" tabindex="-1">什么是共建者 <a class="header-anchor" href="#什么是共建者" aria-label="Permalink to &quot;什么是共建者&quot;">​</a></h1><ul><li>共建者是与我们合作，会共同参与产品的落地探索、功能测试、优化迭代中的企业合作伙伴</li><li>他们有企业正在面临的真实问题，提供真实的业务场景，与我们一起共创解决方案</li></ul><h1 id="共建者对我们的意义" tabindex="-1">共建者对我们的意义 <a class="header-anchor" href="#共建者对我们的意义" aria-label="Permalink to &quot;共建者对我们的意义&quot;">​</a></h1><ul><li>通过深度使用和真实反馈，帮助我们优化产品及体验</li><li>建立稳固的合作关系，共同成长与发展</li></ul><h1 id="共建者们-持续招募中" tabindex="-1">共建者们（持续招募中） <a class="header-anchor" href="#共建者们-持续招募中" aria-label="Permalink to &quot;共建者们（持续招募中）&quot;">​</a></h1><p>已覆盖保险、美业、珠宝、教培行业，期待更多共建伙伴加入~</p><p>人保合肥分公司，中国人民保险集团股份有限公司(简称“中国人保”)由与共和国同生共长的中国人民保险公司发展变革而来。公司成立于1949年10月20日，是新中国保险事业的开拓者和奠基人，见证了新中国保险业从小到大、由弱变强的发展历程。</p><p>百丽雅身心健康产业集团，始创于1992年，目前已经成长为国内国际领先的高端身心健康领军品牌。公司定位于身心健康产业，以“中国美业 卓越全球”为集团愿景，经过近三十年的砥砺前行，战略拓展，目前百丽雅已经形成集生活美容、预防医学、医疗美容、健康管理、教育产业、生物科技为一体的集团公司。</p><p>2005年创立于北京的泰式SPA</p><p>iSpa是北京第一家泰国大使馆认证的泰式SPA，是中国境内唯一同时获得JW万豪、希尔顿、洲际、威斯汀、君悦五大酒店品牌进驻许可的SPA品牌，在全国核心城市共计约30家五星级酒店开设直营专属SPA馆。</p><p>致力于打造全球知名医美抗衰老品牌企业。</p><p>2012年7月柏荟成立，2013年上海旗舰总院在汾阳路120号启幕。从梧桐树下开启星辰大海，至今开设10家专科医美连锁机构，1家高定美学艺术中心，业务辐射全国30多个主要城市，在医疗服务领域中勾勒出一副浩瀚的璀璨星图。领先行业推出“高定美学理念”，在手法品质同质化时代，希望通过不一样的审美和艺术领衔未来。</p><p>成立至今，柏荟汇聚国际前沿技术、全球医疗专家，整合全球资源，以JCI国际医疗标准为指引，同时建立常态化标准SOP运营体系，整体提升柏荟各板块医疗连锁的专业水平，致力于打造全球知名医美抗衰老品牌企业。</p><p>根本生物科技（上海）有限公司，是基于现代医疗与生命科学的技术密集型创新企业。公司依托中国未来大健康产业蓝海，立足于国民健康风口领域，通过布局再生医疗技术研发转化、生命健康医疗服务、健康及特殊医疗用品食品三大板块，致力于打造中国优质的全域生命健康管理独角兽企业。目前，根本生物整合国际前沿技术和多方医疗资源，已与日本生物治疗研究所、TRT集团等众多国际尖端医学研究机构建立了紧密的合作关系。现有业务涉及细胞制备与存储、再生医学研究与应用、以及iPS细胞及免疫细胞基础研究成果向临床实践和应用的转化。</p><p>名黛创立1994年，到目前为止已经有30年的历史了。目前在太原市有7家门店，主要分布在太原的五星级酒店、高端小区、高端商场。南区有凯宾斯基酒店、丽华酒店、梧桐公寓、；北区有万达文华酒店、摩天石小区。商场店有国际金融中心、万象城商场等等。</p><p>少年得到，一款专为3-15岁青少年提供定制化学习服务的教育App，由得到App团队出品。</p><p>北京四中、人大附中、北师大附中、101中学等众多名校特级教师，精心梳理各学科知识点和考纲重点。</p><p>薛兆丰、怀沙、鲍鹏山、李鹏飞、郝广才、林欣浩、邢立达、徐来、杜萌若等各个知识领域的名师、高手倾力打造音频课程。</p><p>激发孩子学习兴趣、指导孩子学习方法，延伸课堂教学，拓展知识边界。</p><p>帮助有强烈求知欲、探索心的孩子，达成深度理解、助力课后自学、满足升学需求，更能拓展孩子的基础认知，构建完整的知识体系。</p><p>Laurèl于1978年成立于德国慕尼黑，隶属于Laurèl GmbH 集团，由Dirk Reichert先生担任品牌CEO。1995年迎来伊莉莎白·斯古瓦伊格(Elisabeth Schwaiger)担任其设计总监，由此树立起别具一格的品牌形象。Laurèl以女性的柔美为主，传达出“奢华的舒适”，展示出现代女性身上的现代感。Laurèl将女性的自信巧妙地融入时装，带入日常生活和特殊场合。精致的细节设计、活泼的色彩运用及突出曲线的剪裁，无不彰显一个女性对生活的热爱，优雅而自然，独特而迷人。</p><h1 id="如何成为共建者" tabindex="-1">如何成为共建者 <a class="header-anchor" href="#如何成为共建者" aria-label="Permalink to &quot;如何成为共建者&quot;">​</a></h1><h2 id="适合哪些企业" tabindex="-1"><strong>适合哪些企业：</strong> <a class="header-anchor" href="#适合哪些企业" aria-label="Permalink to &quot;**适合哪些企业：**&quot;">​</a></h2><ul><li>一把手重视员工的培训，对 AI 实践有探索欲</li><li>企业内部本就有自己的培训机制</li><li>员工有大量沟通场景（对外销售、服务，对内沟通协作等）</li><li>企业的产品迭代更新快，需要与员工快速适应变化</li></ul><h2 id="成为共建者" tabindex="-1"><strong>成为共建者：</strong> <a class="header-anchor" href="#成为共建者" aria-label="Permalink to &quot;**成为共建者：**&quot;">​</a></h2><p>添加下方企业微信，联系我们即可</p><h2 id="成为推广大使" tabindex="-1">成为推广大使 <a class="header-anchor" href="#成为推广大使" aria-label="Permalink to &quot;成为推广大使&quot;">​</a></h2><p>如果你想将练练推荐给你身边的企业伙伴，或者你本身就是服务于企业的独立咨询机构，想结合练练一起更好服务你的企业客户，可以添加我们的合作企微，成为推广大使，获得专属的身份和权益~</p>',29)])])}const _=e(i,[["render",o]]);export{u as __pageData,_ as default};
